INSERT OR REPLACE INTO tool VALUES('affe86c8247aa500f11736b138f99faba242df8daf1249c1db59af7763fe96f7','https://www.wohngeldrechner.nrw.de/wg/wgrbhtml/WGRBSTRT','Wohngeldrechner',NULL,NULL,'Wohngeld, Rechner',NULL,NULL,'Wohngeld,Rechner','de','<!DOCTYPE html PUBLIC "-//W3C//DTD XHTML 1.0 Transitional//EN" "http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd"> <html xmlns="http://www.w3.org/1999/xhtml" lang="de" xml:lang="de"> <head> <meta http-equiv="Content-Type" content="text/html; charset=iso-8859-1"/> <meta http-equiv="expires" content="0"/> <title>MHKBD Wohngeldrechner</title> <link rel="stylesheet" type="text/css" href="../css/wgrbform.css"/> </head> <body> <div id="rahmen" class="rahmen"> <div id="kopfbereich" class="kopfbereich"> <img src="../gif/wrnwlogo.gif" width="287" height="53" alt="Logo: Ministerium f&uuml;r Heimat, Kommunales, Bau und Digitalisierung des Landes Nordrhein-Westfalen" title="Logo: Ministerium f&uuml;r Heimat, Kommunales, Bau und Digitalisierung des Landes Nordrhein-Westfalen"/> </div> <!-- Ende kopfbereich --> <div id="streifen" class="streifen"></div> <h1 class="textoben">Wohngeldrechner</h1> <div> <p style="font-size:12pt;font-weight:bold;text-align:center;">und</p> <p style="font-size:16pt;color:#bf0000;text-align:center; font-weight:bold;">Wohngeld-Antragstellung online <span style="font-size:12pt;">(nur f&uuml;r Nordrhein-Westfalen)</span> </p> </div> <p class="textmitte"> Bitte klicken Sie zum Starten der jeweiligen Landesversion auf das Wappen des Bundeslandes </p> <div class="clearing"> <ul> <!-- Wappenzeile1 --> <li id="bb" class="wappen"> <a href="WGRBWLKM?BULA=BB" class="black" tabindex="001" title="Link zum Wohngeldrechner Brandenburg"> Brandenburg<br/> <br/> <img class="mitte" src="../gif/wrbbwapp.jpg" alt="Link zum Wohngeldrechner Brandenburg" width="72" height="100" border="0"/> </a> </li> <!-- Ende Brandenburg --> <li id="hh" class="wappen"> <a href="WGRBWLKM?BULA=HH" class="black" tabindex="001" title="Link zum Wohngeldrechner Hamburg"> Hamburg<br/> <br/> <img class="mitte" src="../gif/wrhhwapp.gif" alt="Link zum Wohngeldrechner Hamburg" width="72" height="100" border="0"/> </a> </li> <!-- Ende Hamburg --> <li id="he" class="wappen"> <a href="WGRBWLKM?BULA=HE" class="black" tabindex="002" title="Link zum Wohngeldrechner Hessen"> Hessen <br/> <br/> <img class="mitte" src="../gif/wrhewapp.gif" alt="Link zum Wohngeldrechner Hessen" width="83" height="100" border="0"/> </a> </li> <!-- Ende Hessen --> <li id="ns" class="wappen"> <a href="WGRBWLKM?BULA=NS" class="black" tabindex="004" title="Link zum Wohngeldrechner Niedersachsen"> Niedersachsen<br/> <br/> <img class="mitte" src="../gif/wrnswapp.gif" alt="Link zum Wohngeldrechner Niedersachsen" width="85" height="100" border="0"/> </a> </li> <!-- Ende NS --> </ul> <!-- Ende Wappenzeile1 --> </div> <div class="clearing"> <ul><!-- Wappenzeile2 --> <li id="nw" class="wappen"> <a href="WGRBWLKM?BULA=NW" class="black" tabindex="005" title="Link zum Wohngeldrechner Nordrhein-Westfalen"> Nordrhein-Westfalen<br/> <br/> <img class="mitte" src="../gif/wrnwwapp.gif" alt="Link zum Wohngeldrechner Nordrhein-Westfalen" width="95" height="100" border="0"/> </a> </li> <!-- Ende NW --> <li id="sl" class="wappen"> <a href="WGRBWLKM?BULA=SL" class="black" tabindex="006" title="Link zum Wohngeldrechner Saarland"> Saarland<br/> <br/> <img class="mitte" src="../gif/wrslwapp.gif" alt="Link zum Wohngeldrechner Saarland" width="68" height="100" border="0"/> </a> </li> <!-- Ende SL --> <li id="sh" class="wappen"> <a href="WGRBWLKM?BULA=SH" class="black" tabindex="007" title="Link zum Wohngeldrechner Schleswig Holstein"> Schleswig-Holstein<br/> <br/> <img class="mitte" src="../gif/wrshwapp.gif" alt="Link zum Wohngeldrechner Schleswig Holstein" width="86" height="100" border="0"/> </a> </li> <!-- Ende SH --> <li id="th" class="wappen"> <a href="WGRBWLKM?BULA=TH" class="black" tabindex="008" title="Link zum Wohngeldrechner Th&uuml;ringen"> Th&uuml;ringen<br/> <br/> <img class="mitte" src="../gif/wrthwapp.gif" alt="Link zum Wohngeldrechner Th&uuml;ringen" width="86" height="100" border="0"/> </a> </li> <!-- Ende TH --> </ul> <!-- Ende Wappenzeile2 --> </div> <!-- Ende Wappenzeile2 --> <div class="textuntentest"> <div class="textlinks"> <p class="zehn">Technische Hinweise:<br/> Bei technischen Problemen mit dem Wohngeld&shy;rechner wenden Sie sich bitte an die <a href="WGRBINFO" tabindex="009" title="Link zur Wohngeldrechner-Service-Stelle" class="ohnepfeil">Service-Stelle</a>.</p> </div> <!-- Ende textlinks --> <div class="textrechts"> <p class="zehn">Fachliche Hinweise:<br/> Bei allen fachlichen Fragen zum Wohngeld wenden Sie sich bitte an die zust&auml;ndige Wohn&shy;geldstelle in Ihrer Gemeinde.</p> </div> <!-- Ende textrechts --> </div> <!-- Ende textuntentest --> <div> <p class="copyright" style="clear:both"> <a href="WGRBKINDERZUSCHLAGINFOSEITE">Kinderzuschlag</a> <br/> <a href="WGRBIMPRESSUM">Impressum</a> <br/> <span lang="en"><em>&copy;</em></span><abbr> IT.NRW</abbr> </p> </div> <!-- Ende textunten --> </div> <!-- Ende rahmen --> </body> </html>','class,wohngeldrechner,link,ende,title,href,width,height,wappen,tabindex','auto_processed','2025-09-17T10:22:31Z','2025-09-17T10:22:31Z');
